                  </div>
                  {p.badge && (
                    <div className={`absolute top-2 left-2 px-2 py-0.5 rounded-full text-[9px] font-bold ${p.badge === "Sale" ? "bg-red-500 text-white" : p.badge === "Low stock" ? "bg-amber-500 text-white" : "bg-neutral-900 text-white"}`}>
