/**
 * Agent Thread Nav
 * Category: Communication
 * Tags: agent, chat, thread, tabs, ai, assistant, navigation, intro, greeting
 * Description: Horizontal thread-picker rail at the top with a greeting intro card for new
 * threads. Each chip shows the thread name, agent assignment, and unread count. Selecting a
 * new thread surfaces the agent intro — name, role, and three starter prompts that fill the
 * composer on click. Existing threads show the live conversation below. Handles new, active,
 * unread, and sending states. Mobile-responsive: rail scrolls horizontally, composer stacks.
 *
 * Source: https://raw.githubusercontent.com/gkstrmtm/exhibit/main/components/agent-thread-nav.tsx
 * Index:  https://raw.githubusercontent.com/gkstrmtm/exhibit/main/components.json
 */

import { useCallback, useState } from "react";
import { ChevronRight, Plus, Send } from "lucide-react";

// ─── types ────────────────────────────────────────────────────────────────────

type ThreadStatus = "new" | "active" | "unread";

type Thread = {
  id: number;
  label: string;
  agentName: string;
  agentRole: string;
  status: ThreadStatus;
  unread?: number;
};

type Message = {
  role: "user" | "assistant";
  text: string;
  time: string;
};

// ─── data ─────────────────────────────────────────────────────────────────────

const threads: Thread[] = [
  { id: 1, label: "Auth refactor plan", agentName: "Ora", agentRole: "Planning",  status: "active"           },
  { id: 2, label: "Prompt audit",       agentName: "Vex", agentRole: "Analysis",  status: "unread", unread: 2 },
  { id: 3, label: "Design brief",       agentName: "Ora", agentRole: "Planning",  status: "active"           },
  { id: 4, label: "New thread",         agentName: "Ora", agentRole: "Planning",  status: "new"              },
];

const starters = [
  "Help me plan a feature from scratch",
  "Review my current approach and find gaps",
  "Draft a brief I can hand off to an engineer",
];

const seedMessages = new Map<number, Message[]>([
  [1, [
    { role: "assistant", text: "Route-level auth guards should own the access decision — not the component. If a component is asking 'can I render?', the guard already missed it.", time: "3:14 PM" },
    { role: "user",      text: "Makes sense. Where does token refresh fit?", time: "3:15 PM" },
    { role: "assistant", text: "Token refresh lives in the HTTP interceptor, not the guard. The guard locks the door; the interceptor keeps the key fresh. They should not know about each other.", time: "3:15 PM" },
  ]],
  [2, [
    { role: "assistant", text: "Found 4 coherence issues in your funnel prompts. The confirm state in steps 3 and 5 use different language for the same action — that's the highest-priority fix.", time: "2:41 PM" },
    { role: "user",      text: "Can you list all four?", time: "2:42 PM" },
  ]],
  [3, [
    { role: "assistant", text: "Draft brief is ready. I kept it to one page — goal, constraints, success criteria. Let me know if you want a technical dependencies section added.", time: "1:06 PM" },
  ]],
]);

// ─── component ────────────────────────────────────────────────────────────────

export default function AgentThreadNav() {
  const [activeId, setActiveId] = useState<number>(4); // start on "New thread"
  const [draft, setDraft] = useState("");
  const [sending, setSending] = useState(false);

  const activeThread = threads.find((t) => t.id === activeId)!;
  const messages = seedMessages.get(activeId) ?? [];
  const isNew = activeThread.status === "new";

  const handleSend = useCallback(async () => {
    if (!draft.trim() || sending) return;
    setSending(true);
    await new Promise<void>((r) => setTimeout(r, 600));
    setSending(false);
    setDraft("");
  }, [draft, sending]);

  return (
    <div className="flex min-h-[520px] w-full flex-col overflow-hidden rounded-xl border border-slate-200 bg-white">

      {/* ── thread rail ─────────────────────────────────────────────── */}
      <div className="flex items-center gap-1.5 overflow-x-auto border-b border-slate-100 bg-slate-50 px-3 py-2 [scrollbar-width:none]">
        {threads.map((t) => (
          <button
            key={t.id}
            onClick={() => setActiveId(t.id)}
            className={`relative inline-flex shrink-0 items-center gap-1.5 rounded-full border px-3 py-1.5 text-[12px] font-medium transition-colors ${
              t.id === activeId
                ? "border-slate-900 bg-slate-900 text-white"
                : "border-slate-200 bg-white text-slate-600 hover:border-slate-300 hover:bg-slate-50"
            }`}
          >
            {t.status === "new" ? (
              <>
                <Plus className="h-3 w-3" />
                New thread
              </>
            ) : (
              <>
                {t.label}
                {t.status === "unread" && t.unread ? (
                  <span className="ml-0.5 flex h-4 w-4 items-center justify-center rounded-full bg-blue-500 text-[9px] font-bold text-white">
                    {t.unread}
                  </span>
                ) : null}
              </>
            )}
          </button>
        ))}
      </div>

      {/* ── content ─────────────────────────────────────────────────── */}
      <div className="flex flex-1 flex-col overflow-hidden">

        {/* new thread: agent intro card */}
        {isNew ? (
          <div className="flex flex-1 flex-col items-center justify-center px-5 py-10">
            <div className="w-full max-w-md">

              {/* agent identity */}
              <div className="flex items-center gap-3">
                <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-full bg-slate-900 text-[13px] font-bold text-white">
                  {activeThread.agentName[0]}
                </div>
                <div>
                  <div className="text-[10px] font-medium uppercase tracking-[0.14em] text-slate-400">
                    {activeThread.agentRole} agent
                  </div>
                  <div className="text-[15px] font-semibold text-slate-900">
                    Hi, I'm {activeThread.agentName}
                  </div>
                </div>
              </div>

              <p className="mt-4 text-[13px] leading-relaxed text-slate-500">
                I can help you plan, break down a brief, review your approach, or prepare a spec for handoff. What are we working on?
              </p>

              {/* starter prompts */}
              <div className="mt-5 space-y-2">
                {starters.map((s) => (
                  <button
                    key={s}
                    onClick={() => setDraft(s)}
                    className="flex w-full items-center justify-between rounded-lg border border-slate-200 bg-slate-50 px-4 py-3 text-left text-[13px] text-slate-700 transition-colors hover:border-slate-300 hover:bg-white active:bg-slate-100"
                  >
                    {s}
                    <ChevronRight className="ml-2 h-3.5 w-3.5 shrink-0 text-slate-400" />
                  </button>
                ))}
              </div>
            </div>
          </div>
        ) : (
          /* existing thread: messages */
          <div className="flex-1 space-y-5 overflow-auto px-5 py-5">
            {messages.map((msg, i) => (
              <div key={i} className={`flex ${msg.role === "user" ? "justify-end" : "justify-start"}`}>
                {msg.role === "assistant" && (
                  <div className="mr-2.5 mt-0.5 flex h-6 w-6 shrink-0 items-center justify-center rounded-full bg-slate-900 text-[10px] font-bold text-white">
                    {activeThread.agentName[0]}
                  </div>
                )}
                <div className={`${msg.role === "user" ? "max-w-[72%]" : "min-w-0 flex-1"}`}>
                  {msg.role === "assistant" && (
                    <div className="mb-1 text-[10px] font-medium uppercase tracking-[0.12em] text-slate-400">
                      {activeThread.agentName} · {activeThread.agentRole}
                    </div>
                  )}
                  <div className={`rounded-xl px-3.5 py-2.5 text-[13px] leading-relaxed ${
                    msg.role === "user"
                      ? "bg-slate-900 text-white"
                      : "border border-slate-100 bg-white text-slate-800 shadow-[0_1px_3px_rgba(0,0,0,0.04)]"
                  }`}>
                    {msg.text}
                  </div>
                  <div className={`mt-1 font-mono text-[10px] text-slate-400 ${msg.role === "user" ? "text-right" : ""}`}>
                    {msg.time}
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}

        {/* ── composer ──────────────────────────────────────────────── */}
        <div className="border-t border-slate-100 p-3 sm:p-4">
          <div className="flex items-end gap-2 rounded-xl border border-slate-200 bg-slate-50 px-3.5 py-3 transition-colors focus-within:border-slate-400 focus-within:bg-white">
            <textarea
              rows={1}
              value={draft}
              onChange={(e) => setDraft(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === "Enter" && !e.shiftKey) {
                  e.preventDefault();
                  handleSend();
                }
              }}
              placeholder={`Message ${activeThread.agentName}…`}
              className="flex-1 resize-none bg-transparent text-[13px] text-slate-900 outline-none placeholder:text-slate-400"
            />
            <button
              onClick={handleSend}
              disabled={!draft.trim() || sending}
              aria-label="Send message"
              className={`flex h-9 w-9 shrink-0 items-center justify-center rounded-lg transition-colors sm:h-8 sm:w-8 ${
                draft.trim() && !sending
                  ? "bg-slate-900 text-white active:scale-95"
                  : "bg-slate-200 text-slate-400"
              }`}
            >
              <Send className="h-3.5 w-3.5" />
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

/**
 * AI Conversation Thread
 * Category: Communication
 * Tags: agent, chat, ai, thread, llm, conversation, streaming, typing, response
 * Description: Asymmetric AI conversation layout. AI responses render as full-width prose
 * blocks — left-anchored with agent identity above, generous line-height, no bubble. User
 * messages are compact right-aligned pills. Handles all states: idle, user sending, AI
 * typing (animated dots), AI streamed response, and per-message error with retry. The
 * visual weight difference between AI and user messages makes scan direction unambiguous.
 * Mobile-responsive with 44px touch targets and stacking composer.
 *
 * Source: https://raw.githubusercontent.com/gkstrmtm/exhibit/main/components/ai-conversation-thread.tsx
 * Index:  https://raw.githubusercontent.com/gkstrmtm/exhibit/main/components.json
 */

import { useCallback, useEffect, useRef, useState } from "react";
import { AlertCircle, CornerDownLeft, RefreshCw, Send } from "lucide-react";

// ─── types ────────────────────────────────────────────────────────────────────

type MessageRole = "user" | "assistant";
type MessageStatus = "ok" | "error";

type Message = {
  id: number;
  role: MessageRole;
  text: string;
  time: string;
  status: MessageStatus;
};

// ─── seed data ────────────────────────────────────────────────────────────────

const AGENT_NAME   = "Ora";
const AGENT_ROLE   = "Planning agent";
const AGENT_INITIALS = "O";

let nextId = 5;

const initialMessages: Message[] = [
  {
    id: 1,
    role: "assistant",
    text: "I've reviewed the brief. The biggest gap is that you're describing the interface before locking the workflow. Until you know the exact sequence of decisions a user makes, any layout you commit to is guesswork.",
    time: "2:08 PM",
    status: "ok",
  },
  {
    id: 2,
    role: "user",
    text: "Fair. So start with the decision map first?",
    time: "2:09 PM",
    status: "ok",
  },
  {
    id: 3,
    role: "assistant",
    text: "Exactly. Map the five or six real decisions the user has to make, in order. Then ask what information each decision requires. The layout follows from that — not from what looks good in Figma.",
    time: "2:09 PM",
    status: "ok",
  },
  {
    id: 4,
    role: "user",
    text: "Can you walk me through how to run that exercise?",
    time: "2:10 PM",
    status: "ok",
  },
];

// Simulated AI reply for demo purposes
const simulatedReply =
  "Start by writing the user's goal at the top of a page. Below that, write the first thing they must decide to move forward — not what they want to see, what they must decide. Repeat that for each step until you reach the completion state. If you can't write a clear decision for a step, you're missing information, not design.";

function now() {
  return new Date().toLocaleTimeString("en-US", { hour: "numeric", minute: "2-digit" });
}

// ─── typing indicator ─────────────────────────────────────────────────────────

function TypingDots() {
  return (
    <div className="flex items-center gap-1 px-1 py-1">
      {[0, 1, 2].map((i) => (
        <span
          key={i}
          className="h-1.5 w-1.5 rounded-full bg-slate-400"
          style={{ animation: `pulse 1.2s ease-in-out ${i * 0.2}s infinite` }}
        />
      ))}
      <style>{`@keyframes pulse { 0%,80%,100%{opacity:.3;transform:scale(.8)} 40%{opacity:1;transform:scale(1)} }`}</style>
    </div>
  );
}

// ─── component ────────────────────────────────────────────────────────────────

export default function AiConversationThread() {
  const [messages, setMessages]   = useState<Message[]>(initialMessages);
  const [draft, setDraft]         = useState("");
  const [isTyping, setIsTyping]   = useState(false);
  const bottomRef                 = useRef<HTMLDivElement | null>(null);

  // Scroll to bottom on new messages or typing
  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, isTyping]);

  const sendMessage = useCallback(async (text: string) => {
    if (!text.trim() || isTyping) return;

    const userMsg: Message = {
      id: nextId++,
      role: "user",
      text: text.trim(),
      time: now(),
      status: "ok",
    };

    setMessages((prev) => [...prev, userMsg]);
    setDraft("");
    setIsTyping(true);

    // Simulate AI response latency
    await new Promise<void>((r) => setTimeout(r, 1600));

    setIsTyping(false);
    setMessages((prev) => [
      ...prev,
      {
        id: nextId++,
        role: "assistant",
        text: simulatedReply,
        time: now(),
        status: "ok",
      },
    ]);
  }, [isTyping]);

  const handleRetry = useCallback((id: number) => {
    setMessages((prev) =>
      prev.map((m) => (m.id === id ? { ...m, status: "ok" } : m))
    );
  }, []);

  return (
    <div className="flex min-h-[540px] w-full flex-col overflow-hidden rounded-xl border border-slate-200 bg-white">

      {/* ── header ───────────────────────────────────────────────────── */}
      <div className="flex items-center gap-3 border-b border-slate-100 px-4 py-3">
        <div className="flex h-8 w-8 items-center justify-center rounded-full bg-slate-900 text-[11px] font-bold text-white">
          {AGENT_INITIALS}
        </div>
        <div>
          <div className="text-[13px] font-semibold text-slate-900">{AGENT_NAME}</div>
          <div className="text-[10px] font-medium uppercase tracking-[0.12em] text-slate-400">
            {AGENT_ROLE}
          </div>
        </div>
        <div className="ml-auto flex items-center gap-1.5">
          <span className="h-1.5 w-1.5 rounded-full bg-emerald-400" />
          <span className="text-[11px] text-slate-400">Active</span>
        </div>
      </div>

      {/* ── thread ───────────────────────────────────────────────────── */}
      <div className="flex-1 overflow-auto px-4 py-5 sm:px-5">
        <div className="mx-auto flex max-w-2xl flex-col gap-6">
          {messages.map((msg) => (
            <div key={msg.id}>
              {msg.role === "assistant" ? (
                /*
                 * AI message: full-width prose block.
                 * Agent label sits above. Text gets generous line-height.
                 * Error state shows inline retry — no toast, no redirect.
                 */
                <div className="flex gap-3">
                  <div className="mt-0.5 flex h-6 w-6 shrink-0 items-center justify-center rounded-full bg-slate-100 text-[10px] font-bold text-slate-600">
                    {AGENT_INITIALS}
                  </div>
                  <div className="min-w-0 flex-1">
                    <div className="mb-1.5 text-[10px] font-medium uppercase tracking-[0.12em] text-slate-400">
                      {AGENT_NAME}
                    </div>
                    {msg.status === "error" ? (
                      <div className="flex items-start gap-2 rounded-xl border border-red-100 bg-red-50 px-3.5 py-3">
                        <AlertCircle className="mt-0.5 h-3.5 w-3.5 shrink-0 text-red-400" />
                        <div className="flex-1">
                          <div className="text-[12px] text-red-700">
                            Response failed. The message was not delivered.
                          </div>
                          <button
                            onClick={() => handleRetry(msg.id)}
                            className="mt-1.5 inline-flex items-center gap-1 text-[11px] font-medium text-red-600 hover:text-red-800"
                          >
                            <RefreshCw className="h-3 w-3" />
                            Retry
                          </button>
                        </div>
                      </div>
                    ) : (
                      <div className="rounded-xl border border-slate-100 bg-slate-50/60 px-4 py-3.5 text-[13px] leading-[1.7] text-slate-800">
                        {msg.text}
                      </div>
                    )}
                    <div className="mt-1 font-mono text-[10px] text-slate-400">
                      {msg.time}
                    </div>
                  </div>
                </div>
              ) : (
                /*
                 * User message: compact right-aligned pill.
                 * Contrasts with AI prose via background + alignment.
                 */
                <div className="flex justify-end">
                  <div className="max-w-[70%] sm:max-w-[60%]">
                    <div className="rounded-2xl bg-slate-900 px-4 py-2.5 text-[13px] leading-relaxed text-white">
                      {msg.text}
                    </div>
                    <div className="mt-1 text-right font-mono text-[10px] text-slate-400">
                      {msg.time}
                    </div>
                  </div>
                </div>
              )}
            </div>
          ))}

          {/* typing indicator */}
          {isTyping && (
            <div className="flex gap-3">
              <div className="mt-0.5 flex h-6 w-6 shrink-0 items-center justify-center rounded-full bg-slate-100 text-[10px] font-bold text-slate-600">
                {AGENT_INITIALS}
              </div>
              <div className="min-w-0 flex-1">
                <div className="mb-1.5 text-[10px] font-medium uppercase tracking-[0.12em] text-slate-400">
                  {AGENT_NAME}
                </div>
                <div className="inline-block rounded-xl border border-slate-100 bg-slate-50/60 px-4 py-3.5">
                  <TypingDots />
                </div>
              </div>
            </div>
          )}

          <div ref={bottomRef} />
        </div>
      </div>

      {/* ── composer ─────────────────────────────────────────────────── */}
      <div className="border-t border-slate-100 p-3 sm:p-4">
        <div className="mx-auto max-w-2xl">
          <div className="flex items-end gap-2 rounded-xl border border-slate-200 bg-slate-50 px-3.5 py-3 transition-colors focus-within:border-slate-400 focus-within:bg-white">
            <textarea
              rows={1}
              value={draft}
              onChange={(e) => setDraft(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === "Enter" && !e.shiftKey) {
                  e.preventDefault();
                  sendMessage(draft);
                }
              }}
              placeholder={`Ask ${AGENT_NAME}…`}
              className="flex-1 resize-none bg-transparent text-[13px] text-slate-900 outline-none placeholder:text-slate-400"
            />
            <div className="flex shrink-0 items-center gap-1.5">
              <span className="hidden text-[10px] text-slate-300 sm:inline">
                <CornerDownLeft className="inline h-3 w-3" /> send
              </span>
              <button
                onClick={() => sendMessage(draft)}
                disabled={!draft.trim() || isTyping}
                aria-label="Send message"
                className={`flex h-9 w-9 items-center justify-center rounded-lg transition-colors sm:h-8 sm:w-8 ${
                  draft.trim() && !isTyping
                    ? "bg-slate-900 text-white active:scale-95"
                    : "bg-slate-200 text-slate-400"
                }`}
              >
                <Send className="h-3.5 w-3.5" />
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

/**
 * Agent Handoff Thread
 * Category: Communication
 * Tags: agent, handoff, multi-agent, thread, ai, pipeline, coordination, workflow
 * Description: A multi-agent conversation thread where distinct agents take turns and
 * handoff moments are explicit events in the timeline. Each agent has a unique identity
 * chip and color key. Handoff events appear as labeled dividers — not just a different
 * avatar — so the baton-pass reads immediately. Shows three-agent pipeline: Triage →
 * Research → Synthesis. Agents can be in active, waiting, or done states. Thread is
 * scrollable; active agent indicator shows who holds the floor. Mobile-responsive.
 *
 * Source: https://raw.githubusercontent.com/gkstrmtm/exhibit/main/components/agent-handoff-thread.tsx
 * Index:  https://raw.githubusercontent.com/gkstrmtm/exhibit/main/components.json
 */

import { useState } from "react";
import { ArrowRight, CheckCircle2, Clock } from "lucide-react";

// ─── agent registry ───────────────────────────────────────────────────────────

type AgentStatus = "active" | "waiting" | "done";

type Agent = {
  id: string;
  name: string;
  role: string;
  initial: string;
  bg: string;       // Tailwind bg class
  text: string;     // Tailwind text class
  border: string;   // Tailwind border class
  dot: string;      // Tailwind bg dot class
};

const AGENTS: Record<string, Agent> = {
  triage: {
    id: "triage",
    name: "Vex",
    role: "Triage",
    initial: "V",
    bg: "bg-violet-100",
    text: "text-violet-700",
    border: "border-violet-200",
    dot: "bg-violet-500",
  },
  research: {
    id: "research",
    name: "Arc",
    role: "Research",
    initial: "A",
    bg: "bg-blue-100",
    text: "text-blue-700",
    border: "border-blue-200",
    dot: "bg-blue-500",
  },
  synthesis: {
    id: "synthesis",
    name: "Ora",
    role: "Synthesis",
    initial: "O",
    bg: "bg-emerald-100",
    text: "text-emerald-700",
    border: "border-emerald-200",
    dot: "bg-emerald-500",
  },
};

// ─── timeline items ───────────────────────────────────────────────────────────

type MessageItem = {
  kind: "message";
  agentId: string;
  text: string;
  time: string;
};

type HandoffItem = {
  kind: "handoff";
  fromId: string;
  toId: string;
  reason: string;
  time: string;
};

type ThreadItem = MessageItem | HandoffItem;

const thread: ThreadItem[] = [
  {
    kind: "message",
    agentId: "triage",
    text: "Reviewing the incoming request. The ask is ambiguous — it conflates a UI problem with a data modeling problem. I'm going to classify this as a workflow gap before it surfaces as both.",
    time: "10:41 AM",
  },
  {
    kind: "message",
    agentId: "triage",
    text: "Classification confirmed: the user is describing symptoms of a missing intermediate state, not a layout failure. Handing off to Research with the constraint set.",
    time: "10:42 AM",
  },
  {
    kind: "handoff",
    fromId: "triage",
    toId: "research",
    reason: "Workflow gap identified. Constraint set attached. Research to find precedents and data shape.",
    time: "10:42 AM",
  },
  {
    kind: "message",
    agentId: "research",
    text: "Received. Looking at three known patterns for intermediate workflow states: draft/pending/committed, staged/confirmed/dispatched, and queued/in-progress/resolved.",
    time: "10:44 AM",
  },
  {
    kind: "message",
    agentId: "research",
    text: "The draft/pending/committed model fits best — it maps directly to the approval chain described in the brief. The data shape needs three status fields minimum: intent, review_state, and dispatch_state. Handing off to Synthesis with the model.",
    time: "10:46 AM",
  },
  {
    kind: "handoff",
    fromId: "research",
    toId: "synthesis",
    reason: "State model selected. Three-field schema defined. Synthesis to produce the final recommendation.",
    time: "10:46 AM",
  },
  {
    kind: "message",
    agentId: "synthesis",
    text: "Combining triage classification and research model. Final recommendation: implement a three-state approval chain (Draft → Pending Review → Dispatched). Surface each state as a distinct lane in the queue view — not as filter pills. The visual separation carries the workflow logic without additional chrome.",
    time: "10:48 AM",
  },
];

// ─── agent status bar ─────────────────────────────────────────────────────────

const agentStatuses: { id: string; status: AgentStatus }[] = [
  { id: "triage",    status: "done"    },
  { id: "research",  status: "done"    },
  { id: "synthesis", status: "active"  },
];

function AgentStatusPip({ agent, status }: { agent: Agent; status: AgentStatus }) {
  return (
    <div className={`flex items-center gap-2 rounded-full border px-3 py-1.5 ${agent.border} ${agent.bg}`}>
      <span className={`text-[11px] font-semibold ${agent.text}`}>
        {agent.name}
      </span>
      <span className={`text-[10px] font-medium uppercase tracking-[0.12em] ${agent.text} opacity-70`}>
        {agent.role}
      </span>
      {status === "active"  && <span className={`h-1.5 w-1.5 rounded-full ${agent.dot} animate-pulse`} />}
      {status === "done"    && <CheckCircle2 className={`h-3 w-3 ${agent.text}`} />}
      {status === "waiting" && <Clock className={`h-3 w-3 ${agent.text} opacity-60`} />}
    </div>
  );
}

// ─── component ────────────────────────────────────────────────────────────────

export default function AgentHandoffThread() {
  const [expanded, setExpanded] = useState<Set<number>>(new Set([2, 5])); // handoffs start expanded

  const toggleHandoff = (index: number) => {
    setExpanded((prev) => {
      const next = new Set(prev);
      next.has(index) ? next.delete(index) : next.add(index);
      return next;
    });
  };

  return (
    <div className="w-full max-w-2xl overflow-hidden rounded-xl border border-slate-200 bg-white">

      {/* ── header ───────────────────────────────────────────────────── */}
      <div className="border-b border-slate-100 px-4 py-3 sm:px-5">
        <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
          <div>
            <div className="text-[10px] font-medium uppercase tracking-[0.14em] text-slate-400">
              Active pipeline
            </div>
            <div className="mt-0.5 text-[14px] font-semibold text-slate-900">
              Workflow gap resolution
            </div>
          </div>

          {/* agent status bar */}
          <div className="flex flex-wrap items-center gap-2">
            {agentStatuses.map(({ id, status }) => (
              <AgentStatusPip key={id} agent={AGENTS[id]} status={status} />
            ))}
          </div>
        </div>
      </div>

      {/* ── thread ───────────────────────────────────────────────────── */}
      <div className="space-y-0 overflow-auto px-4 py-5 sm:px-5">
        {thread.map((item, i) => {
          if (item.kind === "message") {
            const agent = AGENTS[item.agentId];
            return (
              <div key={i} className="flex gap-3 pb-5">
                {/* agent avatar */}
                <div className={`mt-0.5 flex h-6 w-6 shrink-0 items-center justify-center rounded-full text-[10px] font-bold ${agent.bg} ${agent.text}`}>
                  {agent.initial}
                </div>

                <div className="min-w-0 flex-1">
                  {/* agent label */}
                  <div className="mb-1.5 flex items-center gap-2">
                    <span className={`text-[11px] font-semibold ${agent.text}`}>{agent.name}</span>
                    <span className="text-[10px] text-slate-400">{agent.role}</span>
                  </div>

                  {/* message body */}
                  <div className={`rounded-xl border px-4 py-3 text-[13px] leading-[1.7] text-slate-800 ${agent.border} bg-slate-50/40`}>
                    {item.text}
                  </div>

                  <div className="mt-1 font-mono text-[10px] text-slate-400">{item.time}</div>
                </div>
              </div>
            );
          }

          // handoff event
          const from  = AGENTS[item.fromId];
          const to    = AGENTS[item.toId];
          const open  = expanded.has(i);

          return (
            <div key={i} className="py-2">
              <button
                onClick={() => toggleHandoff(i)}
                className="flex w-full items-center gap-3 text-left"
              >
                {/* from dot */}
                <span className={`h-2 w-2 shrink-0 rounded-full ${from.dot}`} />

                {/* label */}
                <span className="text-[11px] font-semibold text-slate-500">
                  {from.name} handed off to {to.name}
                </span>

                {/* arrow */}
                <ArrowRight className="h-3 w-3 shrink-0 text-slate-300" />

                {/* to dot */}
                <span className={`h-2 w-2 shrink-0 rounded-full ${to.dot}`} />

                {/* time */}
                <span className="ml-auto font-mono text-[10px] text-slate-300">{item.time}</span>

                {/* expand cue */}
                <span className="text-[10px] text-slate-300">{open ? "▲" : "▼"}</span>
              </button>

              {/* expanded reason */}
              {open && (
                <div className="ml-5 mt-2 rounded-lg border border-slate-100 bg-slate-50 px-3.5 py-2.5">
                  <div className="text-[10px] font-medium uppercase tracking-[0.12em] text-slate-400">
                    Handoff context
                  </div>
                  <div className="mt-1 text-[12px] leading-relaxed text-slate-600">
                    {item.reason}
                  </div>
                </div>
              )}

              {/* visual connector to next message */}
              <div className="ml-1 mt-2 h-4 w-px bg-slate-100" />
            </div>
          );
        })}
      </div>
    </div>
  );
}
